### Step 1: Initialize the Board

```python
def initialize_board():
    board = [[' ' for _ in range(8)] for _ in range(8)]

    # Place black pieces
    for i in [0, 2, 4, 6]:
        for j in [i % 2, (i + 1) % 2]:
            board[i][j] = 'B'

    # Place white pieces
    for i in [7, 5, 3, 1]:
        for j in [(8 - i - 1) % 2, ((8 - i - 1) + 1) % 2]:
            board[i][j] = 'W'

    return board

def print_board(board):
    for row in board:
        print(' '.join(row))
```

### Step 2: Player Turns and Move Validation

```python
def is_valid_move(board, start_pos, end_pos, player):
    i1, j1 = start_pos
    i2, j2 = end_pos

    # Check if the move is within bounds
    if not (0 <= i2 < 8 and 0 <= j2 < 8):
        return False

    # Check if the starting position has a piece of the current player
    if board[i1][j1] != player or board[i1][j1] == ' ':
        return False

    # Check if the ending position is empty
    if board[i2][j2] != ' ':
        return False

    # Check diagonal move for regular pieces
    if (player == 'B' and i1 + 1 == i2) or (player == 'W' and i1 - 1 == i2):
        if j1 + 1 == j2 or j1 - 1 == j2:
            return True

    # Check diagonal move for kings
    if board[i1][j1] in ['Bk', 'Wk']:
        if abs(i1 - i2) == abs(j1 - j2):
            return True

    return False

def get_all_valid_moves(board, player):
    valid_moves = []

    for i in range(8):
        for j in range(8):
            if board[i][j] == player:
                if board[i][j] == 'B':
                    for di, dj in [(-1, -1), (-1, 1)]:
                        new_i, new_j = i + di, j + dj
                        if is_valid_move(board, (i, j), (new_i, new_j), player):
                            valid_moves.append(((i, j), (new_i, new_j)))
                elif board[i][j] == 'W':
                    for di, dj in [(1, -1), (1, 1)]:
                        new_i, new_j = i + di, j + dj
                        if is_valid_move(board, (i, j), (new_i, new_j), player):
                            valid_moves.append(((i, j), (new_i, new_j)))
                elif board[i][j] in ['Bk', 'Wk']:
                    for di, dj in [(-1, -1), (-1, 1), (1, -1), (1, 1)]:
                        new_i, new_j = i + di, j + dj
                        if is_valid_move(board, (i, j), (new_i, new_j), player):
                            valid_moves.append(((i, j), (new_i, new_j)))

    return valid_moves

def make_move(board, start_pos, end_pos):
    i1, j1 = start_pos
    i2, j2 = end_pos

    board[i2][j2] = board[i1][j1]
    board[i1][j1] = ' '
```

### Step 3: Capture and Kinging

```python
def is_capture_move(board, start_pos, end_pos):
    i1, j1 = start_pos
    i2, j2 = end_pos

    if abs(i1 - i2) == 2 and abs(j1 - j2) == 2:
        mid_i, mid_j = (i1 + i2) // 2, (j1 + j2) // 2
        return board[mid_i][mid_j] != ' '

def perform_capture(board, start_pos, end_pos):
    i1, j1 = start_pos
    i2, j2 = end_pos

    mid_i, mid_j = (i1 + i2) // 2, (j1 + j2) // 2
    board[mid_i][mid_j] = ' '

    # Check for further captures
    if is_capture_move(board, (i2, j2), end_pos):
        perform_capture(board, (i2, j2), end_pos)

def king_piece(board, pos):
    i, j = pos

    if board[i][j] == 'B' and i == 0:
        board[i][j] = 'Bk'
    elif board[i][j] == 'W' and i == 7:
        board[i][j] = 'Wk'
```

### Step 4: Game State Detection

```python
def check_win(board):
    if all('W' not in row for row in board) or any(row[0] != 'B' for row in board[:3]):
        return 'Black wins'

    if all('B' not in row for row in board) or any(row[-1] != 'W' for row in board[5:]):
        return 'White wins'

    return None

def check_draw(board):
    valid_moves = get_all_valid_moves(board, 'B') + get_all_valid_moves(board, 'W')
    return len(valid_moves) == 0
```

