        player = 'B'
        start_pos, end_pos = input(f"Player {player}, enter your move (e.g., 1-3 2-4): ").split()
        start_pos = tuple(map(int, start_pos.split('-')))
        end_pos = tuple(map(int, end_pos.split('-')))

        if is_valid_move(board, start_pos, end_pos, player):
            make_move(board, start_pos, end_pos)

            if is_capture_move(board, start_pos, end_pos):
                perform_capture(board, start_pos, end_pos)

            if (player == 'B' and end_pos[0] == 7) or (player == 'W' and end_pos[0] == 0):
                king_piece(board, end_pos)
        else:
            print("Invalid move. Try again.")

        player = 'W'

if __name__ == "__main__":
    main()
